// Multi-persona critique → synthesis: improve and polish the codex-workflows
// --gui feature — the self-contained HTML run viewer (runner/bin/view-run.js) and
// its live --watch / --gui integration. Eight diverse design/UX/engineering
// personas read the source and critique from their lens; a lone synthesizer
// consolidates into one prioritized, implementable polish plan.
//
//   node runner/bin/run-workflow.js polish-gui.workflow.js --frontier --auto-effort \
//     --sandbox read-only --budget 8000000

export const meta = {
  name: "polish-gui",
  description: "Diverse multi-persona deliberation to improve + polish the --gui HTML run viewer",
  phases: [
    { title: "Critique", detail: "8 design/UX/eng personas critique the GUI in parallel" },
    { title: "Synthesize", detail: "reconcile into one prioritized, implementable polish plan" },
  ],
};

const FEATURE = [
  "The --gui feature is a SELF-CONTAINED HTML run viewer for a multi-agent Codex workflow run, generated by runner/bin/view-run.js and opened in the browser.",
  "It has TWO views (toggle top-right): ◇ Map — an execution graph (orchestrator → one row of parallel agents per phase → barrier merges → result, with SVG connectors, zoom/pan, Fit, and a slide-in drawer per agent node); ☰ Tree — a Run→Phase→Agent sidebar + a dense detail pane.",
  "Dark + Light (cream) themes (top-right toggle). Per-agent metrics (tokens/time/model/effort) show per agent, phase, and run. Results render generically: arrays-of-objects → tables, palette → color swatches, severity/effort → badges, 1–10 → score pills, plus a raw-JSON toggle.",
  "LIVE mode: `view-run.js <dir> --watch` rebuilds the HTML as the run's journal + event sidecar grow, and the page currently uses a `<meta http-equiv=refresh content=2>` full-page reload to pick up changes. Running (in-flight) agents are merged from the event stream and shown amber + pulsing with elapsed time. `run-workflow.js --gui` auto-opens this viewer and keeps it live, settling to a static render when the run finishes.",
].join("\n- ");

const CONSTRAINTS = [
  "Source to READ (read-only sandbox, cwd = repo root): runner/bin/view-run.js (the inlined CSS string + the `APP` client JS render functions — map, tree, drawer, value renderer, zoom/pan), runner/bin/run-workflow.js (the --gui spawn + teardown), runner/src/runModel.js (buildLiveRunModel + live/event-stream state).",
  "HARD constraint: the output must stay a SINGLE self-contained HTML file — CSS + the run data (JSON) + JS are all inlined; NO external resources (no CDN, no web fonts beyond a system stack, no network calls), so it works offline opened as a file://.",
  "Vanilla JS only — a tiny `h()` DOM builder, no framework, no build step (the runner is zero-dependency Node).",
  "Audience: a developer watching and inspecting a live or finished multi-agent run. The bar is a fast, legible, polished dev tool (think Linear / Vercel / a great observability UI).",
  "Consider BOTH the static finished-run experience AND the live --watch experience (smoothness, what updates, state preservation).",
];

const PERSONAS = [
  { key: "web-ux", brief: "a high-end product web designer. Obsess over visual polish and the 'expensive' feel: typography scale, spacing rhythm, color, depth/shadow, borders, restraint, and tasteful motion — what separates a polished dev tool from a default one." },
  { key: "dataviz-dag", brief: "a data-visualization & graph-layout expert. Focus on the execution MAP: node/edge clarity, how the DAG reads at a glance and at scale (wide fan-outs, many phases), the +N-more collapse, the SVG connectors, and zoom/pan/Fit ergonomics." },
  { key: "frontend-eng", brief: "a senior frontend engineer focused on performance + robustness. Scrutinize the vanilla-JS render path, DOM building, render cost for large runs, the self-contained-file constraint, and the cost/jank of the --watch rebuild + full-page reload." },
  { key: "realtime-ux", brief: "a real-time dashboard / live-ops UX designer. Scrutinize the LIVE --watch experience: the 2s full-page <meta refresh> RELOADS the whole page — what state does that destroy (zoom/pan, scroll, selected node, open drawer, chosen theme/view)? How should a live monitor update without yanking the user? Running-agent feedback, smoothness, at-a-glance progress." },
  { key: "a11y", brief: "an accessibility specialist. Audit contrast (both themes), keyboard navigation + focus, screen-reader semantics, color-only signals, hit targets, and the pulsing running-agent animation vs prefers-reduced-motion." },
  { key: "interaction", brief: "an interaction designer. Scrutinize navigation and drill-down: the map↔tree toggle, the agent drawer, the zoom/pan/Fit controls and keys, discoverability, click targets, and how a user moves from overview to a single agent's result and back." },
  { key: "info-arch", brief: "an information architect for dense data. Focus on the Tree view and the generic RESULT rendering (tables, palette swatches, severity/effort badges, score pills, raw-JSON): scannability, hierarchy, and how well an agent's structured output reads." },
  { key: "minimalist-brand", brief: "a minimalist with a strong brand/aesthetic sense. Judge cohesion and restraint: the dark + cream themes, identity, what to remove, and whether every element earns its place while staying complete." },
];

const CRITIQUE = {
  type: "object",
  additionalProperties: false,
  required: ["persona", "verdict", "top_issues", "specific_changes", "one_big_idea"],
  properties: {
    persona: { type: "string" },
    verdict: { type: "string", description: "one-line overall take on the current --gui" },
    top_issues: {
      type: "array",
      items: {
        type: "object",
        additionalProperties: false,
        required: ["area", "issue", "severity", "fix"],
        properties: {
          area: { type: "string", description: "e.g. map, tree, drawer, themes, live/watch, results, perf, a11y, typography, color, motion" },
          issue: { type: "string" },
          severity: { type: "string", enum: ["high", "medium", "low"] },
          fix: { type: "string", description: "the concrete change (CSS rule, JS behavior, layout, interaction)" },
        },
      },
    },
    specific_changes: { type: "array", items: { type: "string", description: "concrete, implementable change to view-run.js / run-workflow.js (be specific: selectors, properties, render logic, file:line if you can)" } },
    one_big_idea: { type: "string", description: "the single highest-impact improvement you'd make to --gui" },
  },
};

phase("Critique");
const critiques = await parallel(
  PERSONAS.map((p) => () =>
    agent(
      `You are ${p.brief}\n\n` +
        `Critique and propose concrete improvements to the codex-workflows --gui feature. Read the source to ground your proposal in what's implementable.\n\n` +
        `THE FEATURE:\n- ${FEATURE}\n\n` +
        `CONSTRAINTS:\n- ${CONSTRAINTS.join("\n- ")}\n\n` +
        `From YOUR perspective, give your sharpest critique and the most impactful, concretely implementable improvements. Avoid generic advice; cite specific code (view-run.js CSS/APP) where you can.`,
      { label: "critique:" + p.key, sandbox: "read-only", schema: CRITIQUE },
    ),
  ),
);
const valid = critiques.filter(Boolean);
log(`collected ${valid.length}/${PERSONAS.length} persona critiques`);

phase("Synthesize");
const SYNTH = {
  type: "object",
  additionalProperties: false,
  required: ["headline", "prioritized_changes", "quick_wins", "conflicts_resolved", "dropped"],
  properties: {
    headline: { type: "string", description: "the core recommendation for polishing --gui, in one line" },
    prioritized_changes: {
      type: "array",
      description: "ordered, implementable changes (mostly to runner/bin/view-run.js)",
      items: {
        type: "object",
        additionalProperties: false,
        required: ["change", "why", "where", "effort", "impact"],
        properties: {
          change: { type: "string" },
          why: { type: "string" },
          where: { type: "string", description: "file / function / area to touch" },
          effort: { type: "string", enum: ["S", "M", "L"] },
          impact: { type: "string", enum: ["high", "medium", "low"] },
        },
      },
    },
    quick_wins: { type: "array", items: { type: "string", description: "high-impact, low-effort changes to do first" } },
    conflicts_resolved: { type: "array", items: { type: "string", description: "where personas disagreed and how you decided" } },
    dropped: { type: "array", items: { type: "string", description: "ideas considered and rejected, with why" } },
  },
};
const synthesis = await agent(
  `You are a principal design engineer consolidating ${valid.length} persona critiques into ONE polished, prioritized plan to improve the codex-workflows --gui (the self-contained HTML run viewer).\n\n` +
    `Constraints (unchanged):\n- ${CONSTRAINTS.join("\n- ")}\n\n` +
    `Reconcile the proposals: keep what genuinely improves the tool, resolve conflicts decisively, drop gimmicks, and respect the single-self-contained-file + vanilla-JS constraints. Lead with high-impact, low-risk polish (quick wins), and call out the biggest structural improvement (especially the live --watch experience). Produce an ordered, implementable change list for runner/bin/view-run.js (and run-workflow.js where needed).\n\n` +
    `PERSONA CRITIQUES:\n\n` +
    valid
      .map((c, i) => `### [${i + 1}] ${c.persona}\nVerdict: ${c.verdict}\nBig idea: ${c.one_big_idea}\nTop issues: ${(c.top_issues || []).map((t) => `(${t.severity}) ${t.area}: ${t.issue} → ${t.fix}`).join(" | ")}\nChanges: ${(c.specific_changes || []).join(" · ")}`)
      .join("\n\n"),
  { label: "synthesize:plan", schema: SYNTH },
);

return { synthesis, persona_count: valid.length, critiques: valid };
